logotype.css_complete:
/* ── UNRLVL Logotype — copy this block exactly ── */
@keyframes chevron-blink {
  0%, 49% { opacity: 1; }
  50%, 100% { opacity: 0; }
}
.lt-logotype {
  font-family: 'Bebas Neue', sans-serif;
  letter-spacing: 0.04em;
  line-height: 1;
  white-space: nowrap;
}
.lt-un, .lt-ille {
  color: #F2F0EC;
}
.lt-chevron {
  color: #00FFD1;
  animation: chevron-blink 1s step-start infinite;
  display: inline-block;
  transform: scaleY(1.45) scaleX(0.72);
  transform-origin: center;
  letter-spacing: 0;
  margin: 0 -0.01em;
}
.lt-studio {
  color: rgba(242,240,236,0.32);
  font-size: 0.72em;
  letter-spacing: 0.14em;
  margin-left: 0.18em;
}
/* Sizes */
.lt-logotype.size-nav    { font-size: 20px; }
.lt-logotype.size-footer { font-size: 28px; }
.lt-logotype.size-inline { font-size: 16px; }

